// 函數原型
回傳值 = RSI(數列, 期數)

// 範例：6 日 RSI
value1 = RSI(Close, 6);

// 跨頻率：在日線圖取週線 RSI
value2 = xf_RSI("W", GetField("Close","W"), 6);

input: FastLen(6), SlowLen(12);
variable: rsi6(0), rsi12(0);
rsi6  = RSI(Close, FastLen);
rsi12 = RSI(Close, SlowLen);
Plot1(rsi6,  "RSI快線");
Plot2(rsi12, "RSI慢線");
Plot3(70, "超買線");
Plot4(30, "超賣線");

// 快線由下往上穿越慢線 = 黃金交叉
if rsi6 cross above rsi12
then ret = 1;

// 加上超賣位階：更可靠的低檔買進訊號
if rsi6 cross above rsi12
   and rsi6 < 50
then ret = 1;
